import{c as e,Q as a,j as s,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Routines — 排程自動化完整指南","description":"","frontmatter":{"title":"Routines — 排程自動化完整指南","source":"https://code.claude.com/docs/en/routines","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/11-routines.md","filePath":"research/best-practices/11-routines.md","lastUpdated":1779935873000}'),r={name:"research/best-practices/11-routines.md"};function o(n,t,d,l,h,c){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="routines-—-排程自動化完整指南" tabindex="-1">Routines — 排程自動化完整指南 <a class="header-anchor" href="#routines-—-排程自動化完整指南" aria-label="Permalink to &quot;Routines — 排程自動化完整指南&quot;">​</a></h1><blockquote><p>來源：<a href="https://code.claude.com/docs/en/routines" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/routines</a> 收錄日期：2026-05-01 涵蓋：Scheduled / API trigger / GitHub Webhook 三種觸發模式、Routine 建立流程、管理操作、使用限額</p></blockquote><hr><h2 id="什麼是-routine" tabindex="-1">什麼是 Routine？ <a class="header-anchor" href="#什麼是-routine" aria-label="Permalink to &quot;什麼是 Routine？&quot;">​</a></h2><p>Routine 是一個儲存的 Claude Code 設定：prompt、一或多個 repository、及一組 connector，一次設定後自動反覆執行。Routine 跑在 <strong>Anthropic 管理的雲端基礎設施</strong>，筆電關掉仍可持續運作。</p><blockquote><p>狀態：Research Preview，行為、限額和 API 介面可能異動。<br><strong>W16（v2.1.105–113）</strong>：Routines Web UI 完整推出，三種觸發模式（定時時間、GitHub event、API endpoint）全部可用；每個 routine 有獨立的 tokenized <code>/fire</code> endpoint。範例：<code>/schedule daily PR review at 9am</code>。</p></blockquote><p>每個 Routine 可以附加一或多個觸發器：</p><table tabindex="0"><thead><tr><th>觸發類型</th><th>說明</th></tr></thead><tbody><tr><td><strong>Scheduled</strong></td><td>定期排程（hourly / daily / weekly），或一次性指定時間點執行</td></tr><tr><td><strong>API</strong></td><td>透過 HTTP POST 到專屬 endpoint 按需觸發</td></tr><tr><td><strong>GitHub</strong></td><td>對應 repository event（PR、Release 等）自動觸發</td></tr></tbody></table><p>同一個 Routine 可混用多種觸發器。例如：PR review Routine 可以每晚執行、也可從 deploy script 觸發、也可對每個新 PR 觸發。</p><p><strong>適用方案</strong>：Pro、Max、Team、Enterprise（需啟用 Claude Code on the web）。<br><strong>管理入口</strong>：<a href="https://claude.ai/code/routines" target="_blank" rel="noreferrer">claude.ai/code/routines</a> 或 CLI <code>/schedule</code>。</p><hr><h2 id="常見使用情境" tabindex="-1">常見使用情境 <a class="header-anchor" href="#常見使用情境" aria-label="Permalink to &quot;常見使用情境&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>觸發方式</th><th>說明</th></tr></thead><tbody><tr><td><strong>Backlog 自動維護</strong></td><td>Schedule（每週日）</td><td>讀取新 issue → 貼標 → 指派負責人 → Slack 摘要</td></tr><tr><td><strong>Alert 分診</strong></td><td>API（監控工具呼叫）</td><td>收 alert payload → 拉 stack trace → 比對近期 commit → 開 draft PR</td></tr><tr><td><strong>客製 Code Review</strong></td><td>GitHub（PR opened）</td><td>套用 team checklist → 留 inline comment → 加摘要留言</td></tr><tr><td><strong>Deploy 驗證</strong></td><td>API（CD pipeline）</td><td>跑 smoke test → 掃 error log → 貼 go/no-go 到 release channel</td></tr><tr><td><strong>文件 drift 偵測</strong></td><td>Schedule（每週）</td><td>掃合併 PR → 標出 API 變更對應文件 → 開更新 PR</td></tr><tr><td><strong>SDK 跨語言 port</strong></td><td>GitHub（PR merged）</td><td>一個 SDK 合併後自動 port 到另一語言 SDK，開配對 PR</td></tr></tbody></table><hr><h2 id="建立-routine" tabindex="-1">建立 Routine <a class="header-anchor" href="#建立-routine" aria-label="Permalink to &quot;建立 Routine&quot;">​</a></h2><h3 id="三個入口-同步到同一帳號" tabindex="-1">三個入口（同步到同一帳號） <a class="header-anchor" href="#三個入口-同步到同一帳號" aria-label="Permalink to &quot;三個入口（同步到同一帳號）&quot;">​</a></h3><ol><li><strong>Web</strong>：<a href="https://claude.ai/code/routines" target="_blank" rel="noreferrer">claude.ai/code/routines</a> → New routine</li><li><strong>Desktop App</strong>：側邊欄 Routines → New routine → 選 <strong>Remote</strong>（Local = Desktop 本機任務）</li><li><strong>CLI</strong>：<code>/schedule</code> 或 <code>/schedule &lt;自然語言描述&gt;</code></li></ol><h3 id="建立流程-web-表單" tabindex="-1">建立流程（Web 表單） <a class="header-anchor" href="#建立流程-web-表單" aria-label="Permalink to &quot;建立流程（Web 表單）&quot;">​</a></h3><ol><li><strong>命名 + Prompt</strong>：Routine 自主執行，prompt 必須完整自給、明確說明目標與成功定義。表單含 model selector。</li><li><strong>選 Repository</strong>：加入一或多個 GitHub repo。每次執行時從 default branch clone 開始，修改推送到 <code>claude/</code>-prefixed branch。</li><li><strong>選 Environment</strong>：控制 network access、environment variables、setup script（結果有 cache，不每次重跑）。預設提供 Default environment。</li><li><strong>選 Trigger</strong>：Schedule、GitHub event、API（任意組合）。</li><li><strong>設定 Connectors &amp; Permissions</strong>：所有已連接的 MCP connector 預設全部包含，按需移除。啟用 <strong>Allow unrestricted branch pushes</strong> 允許推送到非 <code>claude/</code> 前綴分支。</li></ol><h3 id="重要安全注意" tabindex="-1">重要安全注意 <a class="header-anchor" href="#重要安全注意" aria-label="Permalink to &quot;重要安全注意&quot;">​</a></h3><ul><li>Routine 以自主模式執行（無 permission-mode picker、無 approval prompt）</li><li>Routine 歸屬個人 claude.ai 帳號，不與隊友共享</li><li>計入個人帳號的每日執行次數上限</li><li>所有 commit/PR/connector action 都會以你的身份出現</li></ul><hr><h2 id="觸發器設定" tabindex="-1">觸發器設定 <a class="header-anchor" href="#觸發器設定" aria-label="Permalink to &quot;觸發器設定&quot;">​</a></h2><h3 id="_1-schedule-觸發器" tabindex="-1">1. Schedule 觸發器 <a class="header-anchor" href="#_1-schedule-觸發器" aria-label="Permalink to &quot;1. Schedule 觸發器&quot;">​</a></h3><p><strong>預設頻率</strong>：hourly / daily / weekdays / weekly（時間以本地時區輸入，自動轉換）。<br><strong>自訂 cron</strong>：在表單選最接近的 preset，再用 <code>/schedule update</code> 設定 cron expression（最小間隔 1 小時）。<br><strong>執行延遲</strong>：可能晚幾分鐘，但每個 Routine 的偏移量固定。</p><h4 id="一次性執行-one-off-run" tabindex="-1">一次性執行（One-off Run） <a class="header-anchor" href="#一次性執行-one-off-run" aria-label="Permalink to &quot;一次性執行（One-off Run）&quot;">​</a></h4><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/schedule tomorrow at 9am, summarize yesterday&#39;s merged PRs</span></span>
<span class="line"><span>/schedule in 2 weeks, open a cleanup PR that removes the feature flag</span></span></code></pre></div><ul><li>自動解析自然語言時間，確認後儲存</li><li>執行後自動 disable，UI 標示 <strong>Ran</strong></li><li><strong>不計入每日 Routine 次數上限</strong>（計入一般 session 用量）</li></ul><h3 id="_2-api-觸發器" tabindex="-1">2. API 觸發器 <a class="header-anchor" href="#_2-api-觸發器" aria-label="Permalink to &quot;2. API 觸發器&quot;">​</a></h3><p>每個 Routine 有獨立 HTTP endpoint，POST 後開啟新 session 並回傳 session URL。</p><h4 id="設定步驟" tabindex="-1">設定步驟 <a class="header-anchor" href="#設定步驟" aria-label="Permalink to &quot;設定步驟&quot;">​</a></h4><ol><li>編輯 Routine → Add another trigger → API</li><li>複製 URL → 點 <strong>Generate token</strong>（token 只顯示一次，立即儲存）</li><li>要輪換或撤銷 token：回同一視窗點 Regenerate / Revoke</li></ol><h4 id="呼叫範例" tabindex="-1">呼叫範例 <a class="header-anchor" href="#呼叫範例" aria-label="Permalink to &quot;呼叫範例&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.anthropic.com/v1/claude_code/routines/trig_01ABCDEFGHJKLMNOPQRSTUVW/fire</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-ant-oat01-xxxxx&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;anthropic-beta: experimental-cc-routine-2026-04-01&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;anthropic-version: 2023-06-01&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;text&quot;: &quot;Sentry alert SEN-4521 fired in prod. Stack trace attached.&quot;}&#39;</span></span></code></pre></div><p><strong>回傳</strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;routine_fire&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claude_code_session_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;session_01HJKLMNOPQRSTUVWXYZ&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claude_code_session_url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://claude.ai/code/session_01HJKLMNOPQRSTUVWXYZ&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>text</code> 欄位：可選，傳入 alert body 等 run-specific context（純文字，不解析結構）</li><li>Beta header：<code>experimental-cc-routine-2026-04-01</code>（breaking changes 換新日期 header，舊版保留至少兩個版本）</li><li>完整 API reference：<a href="https://platform.claude.com/docs/en/api/claude-code/routines-fire" target="_blank" rel="noreferrer">platform.claude.com/docs/en/api/claude-code/routines-fire</a></li></ul><h3 id="_3-github-webhook-觸發器" tabindex="-1">3. GitHub Webhook 觸發器 <a class="header-anchor" href="#_3-github-webhook-觸發器" aria-label="Permalink to &quot;3. GitHub Webhook 觸發器&quot;">​</a></h3><blockquote><p>Research Preview 期間：GitHub event 有每 Routine 和每帳號的每小時上限，超出則丟棄。<br> 需要安裝 Claude GitHub App（與 <code>/web-setup</code> 的 clone 授權不同）。</p></blockquote><h4 id="支援的事件" tabindex="-1">支援的事件 <a class="header-anchor" href="#支援的事件" aria-label="Permalink to &quot;支援的事件&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Event</th><th>觸發時機</th></tr></thead><tbody><tr><td>Pull request</td><td>PR 開啟、關閉、指派、貼標、同步等</td></tr><tr><td>Release</td><td>Release 建立、發布、編輯、刪除</td></tr></tbody></table><h4 id="pr-過濾條件" tabindex="-1">PR 過濾條件 <a class="header-anchor" href="#pr-過濾條件" aria-label="Permalink to &quot;PR 過濾條件&quot;">​</a></h4><p>所有條件需同時符合才觸發：</p><table tabindex="0"><thead><tr><th>欄位</th><th>可用 operator</th></tr></thead><tbody><tr><td>Author</td><td>equals / is one of / is not one of</td></tr><tr><td>Title</td><td>contains / starts with / matches regex</td></tr><tr><td>Body</td><td>contains / starts with / matches regex</td></tr><tr><td>Base branch</td><td>equals / contains / matches regex</td></tr><tr><td>Head branch</td><td>equals / contains / matches regex</td></tr><tr><td>Labels</td><td>is one of / is not one of</td></tr><tr><td>Is draft</td><td>true / false</td></tr><tr><td>Is merged</td><td>true / false</td></tr></tbody></table><blockquote><p><strong>注意</strong>：<code>matches regex</code> 測試整個欄位值，不是 substring 匹配。<code>.*hotfix.*</code> 才能匹配含 <code>hotfix</code> 的 title。</p></blockquote><p><strong>過濾範例</strong>：</p><ul><li>Auth 模組 review：base branch = <code>main</code>，head branch contains <code>auth-provider</code></li><li>只處理 ready PR：is draft = <code>false</code></li><li>Label 觸發 backport：labels include <code>needs-backport</code></li></ul><h4 id="session-與-event-的對應" tabindex="-1">Session 與 Event 的對應 <a class="header-anchor" href="#session-與-event-的對應" aria-label="Permalink to &quot;Session 與 Event 的對應&quot;">​</a></h4><p>每個匹配的 GitHub event 產生一個獨立 session，不跨 event 重用 session。</p><hr><h2 id="管理-routine" tabindex="-1">管理 Routine <a class="header-anchor" href="#管理-routine" aria-label="Permalink to &quot;管理 Routine&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td>立即執行</td><td>詳情頁點 <strong>Run now</strong></td></tr><tr><td>暫停 / 恢復</td><td>Repeats 區塊 toggle</td></tr><tr><td>編輯</td><td>點鉛筆圖示 → Edit routine（可改 name、prompt、repo、env、connectors、觸發器）</td></tr><tr><td>刪除</td><td>點刪除圖示（過去的 session 保留在 session 列表）</td></tr></tbody></table><h3 id="cli-管理指令" tabindex="-1">CLI 管理指令 <a class="header-anchor" href="#cli-管理指令" aria-label="Permalink to &quot;CLI 管理指令&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 列出所有 Routines</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 修改現有 Routine</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 立即觸發執行</span></span></code></pre></div><h3 id="repository-與分支設定" tabindex="-1">Repository 與分支設定 <a class="header-anchor" href="#repository-與分支設定" aria-label="Permalink to &quot;Repository 與分支設定&quot;">​</a></h3><ul><li>每次執行從 default branch clone（除非 prompt 另有指定）</li><li>預設只能推送到 <code>claude/</code>-prefixed 分支（防止意外修改主分支）</li><li>啟用 <strong>Allow unrestricted branch pushes</strong> 解除此限制</li></ul><hr><h2 id="使用限額" tabindex="-1">使用限額 <a class="header-anchor" href="#使用限額" aria-label="Permalink to &quot;使用限額&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>說明</th></tr></thead><tbody><tr><td>每日 Routine 次數</td><td>視方案而定，見 <a href="https://claude.ai/code/routines" target="_blank" rel="noreferrer">claude.ai/code/routines</a> 或 <a href="https://claude.ai/settings/usage" target="_blank" rel="noreferrer">claude.ai/settings/usage</a></td></tr><tr><td>超出每日上限</td><td>啟用 extra usage（Settings &gt; Billing）可繼續按用量計費；否則拒絕直到重置</td></tr><tr><td>One-off runs</td><td><strong>不計入每日上限</strong>，計入一般 session 用量</td></tr><tr><td>消耗方式</td><td>與互動 session 相同方式扣用量</td></tr></tbody></table><hr><h2 id="routines-與相關功能比較" tabindex="-1">Routines 與相關功能比較 <a class="header-anchor" href="#routines-與相關功能比較" aria-label="Permalink to &quot;Routines 與相關功能比較&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>執行位置</th><th>Terminal 需開？</th><th>適用情境</th></tr></thead><tbody><tr><td><strong>Routines</strong></td><td>Anthropic 雲端</td><td>不需要</td><td>排程、API 觸發、GitHub 事件</td></tr><tr><td><strong>Desktop scheduled tasks</strong></td><td>本機</td><td>不需要</td><td>本機檔案存取</td></tr><tr><td><strong><code>/loop</code>（CLI）</strong></td><td>本機</td><td>需要</td><td>本地定期執行</td></tr><tr><td><strong>GitHub Actions</strong></td><td>CI 環境</td><td>不需要</td><td>Repository CI pipeline</td></tr></tbody></table><hr><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><a href="https://claude.ai/code/routines" target="_blank" rel="noreferrer">claude.ai/code/routines</a> — Routines 管理入口</li><li><a href="https://code.claude.com/docs/en/desktop-scheduled-tasks" target="_blank" rel="noreferrer">Desktop scheduled tasks</a> — 本機排程任務</li><li><a href="https://code.claude.com/docs/en/claude-code-on-the-web#the-cloud-environment" target="_blank" rel="noreferrer">Cloud environment</a> — 雲端執行環境設定</li><li><a href="https://code.claude.com/docs/en/mcp" target="_blank" rel="noreferrer">MCP connectors</a> — 連接外部服務</li><li><a href="https://code.claude.com/docs/en/github-actions" target="_blank" rel="noreferrer">GitHub Actions</a> — CI pipeline 整合</li><li><a href="https://platform.claude.com/docs/en/api/claude-code/routines-fire" target="_blank" rel="noreferrer">Routine API reference</a> — 完整 API 文件</li></ul>`,65)])])}const k=e(r,[["render",o]]);export{u as __pageData,k as default};
